class UnionFind:
	def __init__(self, n):
		self.n = n
		self.parents = [-1] * n
	
	def find(self, x):
		if self.parents[x] < 0:
			return x
		else:
			self.parents[x] = self.find(self.parents[x])
			return self.parents[x]
	
	def union(self, x, y):
		x = self.find(x)
		y = self.find(y)
		if x == y:
			return
		if self.parents[x] > self.parents[y]:
			x, y = y, x
		self.parents[x] += self.parents[y]
		self.parents[y] = x

n = int(input())
upDown = UnionFind(2*n)
connect = UnionFind(n)

for i in range(n):
	a, b = map(int,input().split())
	
	connect.union(i, a)

	if b == 1:
		upDown.union(i, a)
		upDown.union(n+i, n+a)
	else:
		upDown.union(i, n+a)
		upDown.union(n+i, a)

v = [0 for i in range(2*n)]
for i in range(n):
	v[upDown.find(i)] += 1

ans = 0
for i in range(n):
	if connect.parents[i] < 0:
		targ = -connect.parents[i]
		
		# 矛盾判定
		if upDown.find(i) == upDown.find(i+n):
			continue
		
		# 個数求めるやつ
		tmp = v[upDown.find(i)]
		print(i, targ, tmp)
		ans += max(tmp, targ-tmp)

print(ans)
